// ============================================================
// Internal helper: monotonic timestamp in seconds (uint32_t)
// ============================================================

/**
 * @brief   Returns the current monotonic clock time in whole seconds.
 * @details Uses std::chrono::steady_clock to obtain a monotonic timestamp.
 *          The epoch is the steady_clock epoch (application-relative).
 * @return  uint32_t  Current monotonic time in seconds.
 * @throws  None.
 * @note    Internal helper — not exposed in the public interface.
 */
static uint32_t GetMonotonicTimeSec() noexcept
{
    const auto now{std::chrono::steady_clock::now()};
    const auto duration{now.time_since_epoch()};
    const uint64_t seconds{
        static_cast<uint64_t>(
            std::chrono::duration_cast<std::chrono::seconds>(duration).count())};
    return static_cast<uint32_t>(seconds & static_cast<uint64_t>(0xFFFFFFFFU));
}

/**
 * @brief   Returns the current monotonic clock time in whole milliseconds.
 * @details Uses std::chrono::steady_clock to obtain a monotonic timestamp.
 * @return  uint64_t  Current monotonic time in milliseconds.
 * @throws  None.
 * @note    Internal helper — not exposed in the public interface.
 */
static uint64_t GetMonotonicTimeMs() noexcept
{
    const auto now{std::chrono::steady_clock::now()};
    const auto duration{now.time_since_epoch()};
    return static_cast<uint64_t>(
        std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
}

// ============================================================
// Maximum buffer capacity constants
// ============================================================

/**
 * @brief   Maximum number of entries in the 100 ms CAN ring buffer.
 * @details Derived as (kSampleRate1000Ms / kSampleRate100Ms) * kDefaultPastDataRetentionCount
 *          = (1000 / 100) * 10 = 100 entries.
 */
static constexpr uint32_t kMaxBuffer100Ms{
    (ProbeApp::kSampleRate1000Ms / ProbeApp::kSampleRate100Ms) *
    ProbeApp::kDefaultPastDataRetentionCount};

/**
 * @brief   Maximum number of entries in the 1000 ms CAN ring buffer.
 * @details Equals kDefaultPastDataRetentionCount = 10 entries.
 */
static constexpr uint32_t kMaxBuffer1000Ms{ProbeApp::kDefaultPastDataRetentionCount};

