/**
 * @brief   Constructs ProbeApp with references to communication, variant, and CAN consumer.
 * @details Initializes all internal RAM buffers, validates all dependency pointers, reads
 *          and applies variant configuration, and sets all lifecycle flags to their safe
 *          default states. Throws std::runtime_error if any mandatory dependency is nullptr.
 *          Throws std::invalid_argument if variant configuration returns an inconsistent state.
 *
 *          Initialization sequence:
 *          1. Validate probeCommVariant and canConsumer — fatal if nullptr.
 *          2. Assign all dependency pointers.
 *          3. Initialize all lifecycle flags and counters to safe defaults.
 *          4. Clear all buffer containers and reserve capacity.
 *          5. Apply variant configuration via probeCommVariant.
 *          6. Warn (non-fatal) if probeComm is nullptr.
 *
 * @param[in] comm     Non-owning pointer to the ProbeComm communication handler.
 *                     Must not be nullptr. Lifetime must exceed ProbeApp lifetime.
 * @param[in] variant  Non-owning pointer to the ProbeCommVariant configuration manager.
 *                     Must not be nullptr. Lifetime must exceed ProbeApp lifetime.
 * @param[in] canCons  Non-owning pointer to the CanConsumer shared-memory signal reader.
 *                     Must not be nullptr. Lifetime must exceed ProbeApp lifetime.
 * @throws  std::runtime_error    If variant or canCons pointer is nullptr.
 * @throws  std::invalid_argument If variant configuration returns an inconsistent state.
 * @pre     All three pointer arguments must be valid, fully constructed objects.
 * @post    All internal buffers are allocated and zero-initialized.
 *          isRunning_ == false, shutdownRequested_ == false, collectionStarted_ == false.
 *          msCounter_ == 0.
 * @note    Called by: Main.
 * @requirements SWR-REQ-01-01-002;SWR-REQ-01-01-003;SWR-REQ-01-02-001
 * @rationale Dependency injection via constructor parameters enables unit testing
 *            and avoids hidden global state. Non-owning raw pointers are used here
 *            because lifetime is strictly controlled by Main (MISRA M1 observer pattern).
 * @see     ProbeComm, ProbeCommVariant, CanConsumer
 */
ProbeApp::ProbeApp(ProbeComm* comm,
                   ProbeCommVariant* variant,
                   CanConsumer* canCons)
    : probeComm_{nullptr}
    , probeCommVariant_{nullptr}
    , canConsumer_{nullptr}
    // , canBuffer100ms_null
    // , canBuffer1000ms_null
    // , logDataSetBuffer_null
    // , steadyStateDataBuffer100ms_null
    // , steadyStateDataBuffer1000ms_null
    // , eventSendingBuffer_null
    // , imageDataBuffer_null
    , msCounter_{0U}
    , startupTimeSec_{0U}
    , pastDataRetentionCount_{kDefaultPastDataRetentionCount}
    , isRunning_{false}
    , isDaqCommEstablished_{false}
    , shutdownRequested_{false}
    , collectionStarted_{false}
{
    // Validate critical dependency: variant manager
    if (variant == nullptr)
    {
        throw std::runtime_error(
            "ProbeApp: Fatal initialization error — probeCommVariant pointer is nullptr.");
    }

    // Validate critical dependency: CAN consumer
    if (canCons == nullptr)
    {
        throw std::runtime_error(
            "ProbeApp: Fatal initialization error — canConsumer pointer is nullptr.");
    }

    // Assign injected dependency references
    probeComm_        = comm;
    probeCommVariant_ = variant;
    canConsumer_      = canCons;

    // Initialize all boolean lifecycle flags to safe defaults
    isRunning_.store(false);
    isDaqCommEstablished_.store(false);
    shutdownRequested_.store(false);
    collectionStarted_.store(false);

    // Initialize counters to zero
    msCounter_      = 0U;
    startupTimeSec_ = 0U;

    // Set configurable parameter: past data retention depth
    pastDataRetentionCount_ = kDefaultPastDataRetentionCount;

    // Initialize all buffer containers to empty state
    canBuffer100ms_null.clear();
    canBuffer1000ms_null.clear();
    logDataSetBuffer_null.clear();
    steadyStateDataBuffer100ms_null.clear();
    steadyStateDataBuffer1000ms_null.clear();
    eventSendingBuffer_null.clear();
    imageDataBuffer_null.clear();

    // Reserve capacity to eliminate runtime allocation during cyclic execution
    steadyStateDataBuffer100ms_null.reserve(static_cast<std::size_t>(kMaxBuffer100Ms));
    steadyStateDataBuffer1000ms_null.reserve(static_cast<std::size_t>(kMaxBuffer1000Ms));
    eventSendingBuffer_null.reserve(static_cast<std::size_t>(kDefaultPastDataRetentionCount));

    // Apply variant configuration: read shared memory, then default or dictionary path
    static_cast<void>(probeCommVariant_->ReadVariantCodeFromSharedMemory());
    if (probeCommVariant_->IsVariantReadSuccessful() == false)
    {
        probeCommVariant_->ApplyDefaultVariantCode();
    }
    else
    {
        if (probeCommVariant_->ApplyVariantFeatureFlags() == false)
        {
            probeCommVariant_->ApplyDefaultVariantCode();
        }
    }

    // Validate communication handler availability (non-fatal at construction)
    if (probeComm_ == nullptr)
    {
        // Non-fatal: communication will be established in HandleInitialize
        std::cerr << "ProbeApp: Warning — probeComm pointer is nullptr at construction. "
                     "Communication will be established in HandleInitialize.";
    }
}

